const users = $('Fetch User Metrics').first().json;
const revenue = $('Fetch Revenue Metrics').first().json;
const perf = $('Fetch Performance Card').first().json;
const health = $('Fetch Health').first().json;

const today = new Date().toISOString().split('T')[0];

const newUsers = users.new_users_today ?? users.newUsersToday ?? 0;
const totalUsers = users.total_users ?? users.totalUsers ?? 0;
const premiumUsers = users.premium_users ?? users.premiumUsers ?? 0;
const trialUsers = users.trial_users ?? users.trialUsers ?? 0;

const stars = revenue.total_stars ?? revenue.totalStars ?? 0;
const usd = revenue.total_usd ?? revenue.totalUsd ?? (stars * 0.02).toFixed(2);
const conversions = revenue.trial_conversions ?? revenue.trialConversions ?? 0;

const predMade = perf.predictions_made ?? perf.predictionsMade ?? 0;
const predCorrect = perf.predictions_correct ?? perf.predictionsCorrect ?? 0;
const accuracy = perf.accuracy ?? (predMade > 0 ? ((predCorrect / predMade) * 100).toFixed(1) : '0.0');
const signals = perf.trading_signals ?? perf.tradingSignals ?? 0;
const profitable = perf.profitable_signals ?? perf.profitableSignals ?? 0;

const ticketsOpened = perf.tickets_opened ?? perf.supportTicketsOpened ?? 0;
const ticketsResolved = perf.tickets_resolved ?? perf.supportTicketsResolved ?? 0;

const apiRequests = health.api_requests ?? health.apiRequests ?? health.requestCount ?? 'N/A';
const apiErrors = health.api_errors ?? health.apiErrors ?? health.errorCount ?? 0;
const healthStatus = health.status ?? 'unknown';

const report = `\u{1F4CA} <b>Daily Report \u2014 ${today}</b>

<b>USERS:</b> +${newUsers} new | ${totalUsers} total | ${premiumUsers} premium | ${trialUsers} trial
<b>REVENUE:</b> ${stars} Stars (~$${usd}) | ${conversions} trial conversions
<b>PREDICTIONS:</b> ${predMade} made | ${predCorrect} correct (${accuracy}%)
<b>TRADING:</b> ${signals} signals | ${profitable} profitable
<b>SUPPORT:</b> ${ticketsOpened} opened | ${ticketsResolved} resolved
<b>SYSTEM:</b> ${apiRequests} API requests | ${apiErrors} errors | ${healthStatus}`;

return [{ json: { report } }];

const response = $('Send to Admin Telegram').first().json;
const success = response.ok === true;
const now = new Date().toISOString();
console.log(`[${now}] Daily Owner Report — Telegram send ${success ? 'SUCCESS' : 'FAILED'}`);
return [{ json: { logged: true, success, timestamp: now } }];
